rooted_product_impl <- function(
  g1,
  g2,
  root
) {
  # Argument checks
  ensure_igraph(g1)
  ensure_igraph(g2)
  root <- as_igraph_vs(g2, root)
  if (length(root) != 1) {
    cli::cli_abort(
      "{.arg root} must specify exactly one vertex",
      call = rlang::caller_env()
    )
  }

  on.exit(.Call(R_igraph_finalizer))
  # Function call
  res <- .Call(
    R_igraph_rooted_product,
    g1,
    g2,
    root - 1
  )

  res
}

